/**
 * Notification model — types and interfaces for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. The NotificationService
 * listens for application events and dispatches notifications through registered
 * NotificationAdapter implementations (email, webhook, SMS, etc.).
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications must originate from EventBus events
 * - NotificationPayload must carry all data needed to render the notification
 */

/**
 * Supported notification channel types.
 * Each channel corresponds to a NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'push';

/**
 * Categories of notifications the system can produce.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/**
 * The payload passed to notification adapters for rendering and delivery.
 */
export interface NotificationPayload {
  /** Unique notification identifier. */
  id: string;
  /** The type of notification being sent. */
  type: NotificationType;
  /** Recipient identifier (email address, phone number, webhook URL, etc.). */
  recipient: string;
  /** Notification subject/title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Additional structured data adapters can use for rich rendering. */
  metadata?: Record<string, unknown>;
  /** When the notification was created. */
  createdAt: Date;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The channel used for delivery. */
  channel: NotificationChannel;
  /** The notification that was delivered. */
  notificationId: string;
  /** Error message if delivery failed. */
  error?: string;
  /** Timestamp of the delivery attempt. */
  deliveredAt: Date;
}

/**
 * A persisted notification record combining payload with delivery status.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  metadata?: Record<string, unknown>;
  sentAt: Date;
  delivered: boolean;
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all notification channel
 * implementations must fulfill.
 *
 * Architecture: The NotificationService dispatches notifications through
 * adapters. Each adapter handles one channel (email, webhook, SMS, push).
 * Adapters are registered with the NotificationService and selected based
 * on the channel type.
 *
 * Constraints:
 * - All adapters must implement this interface
 * - Adapters must be stateless with respect to notification delivery
 * - Adapters must return a NotificationResult indicating success or failure
 * - Adapters must not throw exceptions; they must return { success: false, error: ... }
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory rather than
 * sending them through an SMTP server. The interface is real and must
 * be respected by any production implementation.
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  /**
   * Send a notification as an email.
   * Stub: stores the email in-memory instead of sending via SMTP.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const email: EmailMessage = {
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      };

      this.sentEmails.push(email);
      this.logger.info(`Email sent to ${payload.recipient}: ${payload.subject}`);

      return {
        success: true,
        channel: this.channel,
        notificationId: payload.id,
        deliveredAt: email.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        notificationId: payload.id,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven with pluggable adapters.
 * - Subscribes to EventBus events (order:created, order:status-changed, etc.)
 * - Transforms events into NotificationPayload objects
 * - Dispatches payloads through registered NotificationAdapter implementations
 *
 * Constraints:
 * - All notifications originate from EventBus events — no direct calls
 * - All delivery goes through NotificationAdapter implementations
 * - The service does NOT know about specific channels; adapters handle that
 * - Event handlers are registered in the constructor
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the notification ID counter. Used in tests.
 */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private defaultChannel: NotificationChannel = 'email';

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  /**
   * Set the default notification channel.
   */
  setDefaultChannel(channel: NotificationChannel): void {
    this.defaultChannel = channel;
  }

  /**
   * Register event handlers for notification triggers.
   * All events come through EventBus — no other input paths.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.send({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Sending welcome notification for user ${event.user.id}`);

    await this.send({
      type: 'user_welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Falls back to in-memory storage if no adapter is registered for the channel.
   */
  async send(
    params: {
      type: NotificationType;
      recipient: string;
      subject: string;
      body: string;
      metadata?: Record<string, unknown>;
      channel?: NotificationChannel;
    },
  ): Promise<NotificationResult | undefined> {
    const channel = params.channel ?? this.defaultChannel;
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(channel);
    let result: NotificationResult | undefined;

    if (adapter) {
      result = await adapter.send(payload);
    }

    const notification: Notification = {
      id: payload.id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel,
      metadata: payload.metadata,
      sentAt: payload.createdAt,
      delivered: result?.success ?? true,
      error: result?.error,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} sent to ${params.recipient} via ${channel}`);

    return result;
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

